#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int dp[300001][300001];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char S[N + 1];
        scanf("%s", S);
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= K; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j <= K; j++) {
                if (i < N / 2 + 1) {
                    for (int c = 0; c < 26; c++) {
                        int nj = j + (S[i - 1] - 'a' != c);
                        if (nj <= K) {
                            dp[i][nj] = (dp[i][nj] + dp[i - 1][j]) % MOD;
                        }
                    }
                } else {
                    int c = S[N - i] - 'a';
                    int nj = j + (S[i - 1] - 'a' != c);
                    if (nj <= K) {
                        dp[i][nj] = (dp[i][nj] + dp[i - 1][j]) % MOD;
                    }
                }
            }
        }
        int ans = 0;
        for (int j = 0; j <= K; j++) {
            ans = (ans + dp[N][j]) % MOD;
        }
        printf("%d\n", ans);
    }
    return 0;
}

