    static int[][] dp = new int[300001][300001];
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            String S = sc.next();
            for (int i = 0; i <= N; i++) {
                for (int j = 0; j <= K; j++) {
                    dp[i][j] = 0;
                }
            }
            dp[0][0] = 1;
            for (int i = 1; i <= N; i++) {
                for (int j = 0; j <= K; j++) {
                    if (i < N / 2 + 1) {
                        for (int c = 0; c < 26; c++) {
                            int nj = j + (S.charAt(i - 1) - 'a' != c);
                            if (nj <= K) {
                                dp[i][nj] = (dp[i][nj] + dp[i - 1][j]) % MOD;
                            }
                        }
                    } else {
                        int c = S.charAt(N - i) - 'a';
                        int nj = j + (S.charAt(i - 1) - 'a' != c);
                        if (nj <= K) {
                            dp[i][nj] = (dp[i][nj] + dp[i - 1][j]) % MOD;
                        }
                    }
                }
            }
            int ans = 0;
            for (int j = 0; j <= K; j++) {
                ans = (ans + dp[N][j]) % MOD;
            }
            System.out.println(ans);
        }
    }
}

